import React, { useState, useEffect } from "react";
import ab1 from "../assets/ab-hl-1.jpg";
import ab2 from "../assets/ab-hl-2.jpeg";
import ab3 from "../assets/ab-hl-3.jpg";
import ab4 from "../assets/ab-hl-4.jpg";

function About() {
  const images = [ab1, ab2, ab3, ab4];
  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % images.length);
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  return (
    <section
      style={{
        position: "relative",
        height: "400px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        color: "white",
        overflow: "hidden",
        marginTop: "50px", // 👈 gap from Hero section
      }}
    >
      {/* Background Image */}
      <img
        src={images[currentIndex]}
        alt="About Slide"
        style={{
          position: "absolute",
          width: "100%",
          height: "100%",
          objectFit: "cover",
          top: 0,
          left: 0,
          zIndex: -1,
          transition: "opacity 1s ease-in-out",
        }}
      />

      {/* Text Content */}
      <div
        style={{
          textAlign: "center",
          maxWidth: "700px",
          padding: "20px",
          backgroundColor: "rgba(214, 214, 214, 0.6)", // 👈 transparent bg
          borderRadius: "10px",
        }}
      >
        <h2 style={{ marginBottom: "15px" }}>About HEALink</h2>
        <p>
          HEALink was started with a vision to connect people with better
          healthcare solutions. We provide pathology, medicine, consultancy, and
          blood bank services to make healthcare accessible and reliable for
          everyone.
        </p>
      </div>
    </section>
  );
}

export default About;
